103	export class DefaultProcessWorkSurfaceService implements ProcessWorkSurfaceService {
104	  private readonly historySectionReader: HistorySectionReader;
105	  private readonly materialsSectionReader: MaterialsSectionReader;
106	  private readonly sideWorkSectionReader: SideWorkSectionReader;
107	
108	  constructor(
109	    private readonly platformStore: PlatformStore,
110	    private readonly processAccessService: ProcessAccessService,
111	    readers: {
112	      historySectionReader?: HistorySectionReader;
113	      materialsSectionReader?: MaterialsSectionReader;
114	      sideWorkSectionReader?: SideWorkSectionReader;
115	    } = {},
116	  ) {
117	    this.historySectionReader =
118	      readers.historySectionReader ?? new HistorySectionReader(platformStore);
119	    this.materialsSectionReader =
120	      readers.materialsSectionReader ?? new MaterialsSectionReader(platformStore);
121	    this.sideWorkSectionReader =
122	      readers.sideWorkSectionReader ?? new SideWorkSectionReader(platformStore);
123	  }
124	
125	  async getSurface(args: {
126	    actor: AuthenticatedActor;
127	    projectId: string;
128	    processId: string;
129	  }): Promise<ProcessWorkSurfaceResponse> {
130	    const access = await this.processAccessService.assertProcessAccess(args);
131	    const [history, materials, currentRequest, sideWork] = await Promise.all([
132	      this.readHistory(args.processId),
133	      this.readMaterials(args.projectId, args.processId),
134	      this.platformStore.getCurrentProcessRequest({
135	        processId: args.processId,
136	      }),
137	      this.readSideWork(args.processId),
138	    ]);
139	
140	    return processWorkSurfaceResponseSchema.parse({
141	      project: processSurfaceProjectSchema.parse({
142	        projectId: access.project.projectId,
143	        name: access.project.name,
144	        role: access.project.role,
145	      }),
146	      process: buildProcessSurfaceSummary(access.process),
147	      history,
148	      materials,
149	      currentRequest,
150	      sideWork,
151	    });
152	  }
153	
154	  private async readHistory(processId: string): Promise<ProcessHistorySectionEnvelope> {
155	    try {
156	      return await this.historySectionReader.read({ processId });
157	    } catch (error) {
158	      return processHistorySectionEnvelopeSchema.parse({
159	        status: 'error',
160	        items: [],
161	        error: {
162	          code: 'PROCESS_SURFACE_HISTORY_LOAD_FAILED',
163	          message: this.getSectionMessage(error, 'Process history failed to load.'),
164	        },
165	      });
166	    }
167	  }
168	
169	  private async readMaterials(
170	    projectId: string,
171	    processId: string,
172	  ): Promise<ProcessMaterialsSectionEnvelope> {
173	    try {
174	      return await this.materialsSectionReader.read({
175	        projectId,
176	        processId,
177	      });
178	    } catch (error) {
179	      return processMaterialsSectionEnvelopeSchema.parse({
180	        status: 'error',
181	        currentArtifacts: [],
182	        currentOutputs: [],
183	        currentSources: [],
184	        error: {
185	          code: 'PROCESS_SURFACE_MATERIALS_LOAD_FAILED',
186	          message: this.getSectionMessage(error, 'Process materials failed to load.'),
187	        },
188	      });
189	    }
190	  }
191	
192	  private async readSideWork(processId: string): Promise<SideWorkSectionEnvelope> {
193	    try {
194	      return await this.sideWorkSectionReader.read({ processId });
195	    } catch (error) {
196	      return sideWorkSectionEnvelopeSchema.parse({
197	        status: 'error',
198	        items: [],
199	        error: {
200	          code: 'PROCESS_SURFACE_SIDE_WORK_LOAD_FAILED',
201	          message: this.getSectionMessage(error, 'Side work failed to load.'),
202	        },
203	      });
204	    }
205	  }
206	
207	  private getSectionMessage(error: unknown, fallback: string): string {
208	    if (error instanceof SectionError) {
209	      return error.message;
210	    }
211	
212	    if (error instanceof Error && error.message.length > 0) {
213	      return error.message;
214	    }
215	
216	    return fallback;
217	  }
218	}

