662	  private updateProjectSummary(
663	    projectId: string,
664	    update: (project: ProjectSummary) => ProjectSummary,
665	  ): void {
666	    for (const [userId, projects] of this.projectsByUserId.entries()) {
667	      const nextProjects = projects.map((project) =>
668	        project.projectId === projectId ? update(project) : project,
669	      );
670	      this.projectsByUserId.set(userId, nextProjects);
671	    }
672	
673	    const directAccess = this.accessByProjectId.get(projectId);
674	    if (directAccess?.kind === 'accessible') {
675	      this.accessByProjectId.set(projectId, {
676	        kind: 'accessible',
677	        project: update(directAccess.project),
678	      });
679	    }
