682	  private applyStoredProcessActionResult(
683	    processId: string,
684	    result: ProcessActionStoreResult,
685	  ): ProcessActionStoreResult {
686	    for (const [projectId, processes] of this.processesByProjectId.entries()) {
687	      const index = processes.findIndex((process) => process.processId === processId);
688	
689	      if (index === -1) {
690	        continue;
691	      }
692	
693	      const nextProcesses = [...processes];
694	      nextProcesses[index] = result.process;
695	      this.processesByProjectId.set(projectId, nextProcesses);
696	      this.currentRequestsByProcessId.set(processId, result.currentRequest);
697	      this.updateProjectSummary(projectId, (project) => ({
698	        ...project,
699	        lastUpdatedAt: result.process.updatedAt,
700	      }));
701	
702	      return result;
703	    }
704	
705	    return result;
706	  }
