708	  private transitionProcessToRunning(processId: string): ProcessActionStoreResult {
709	    for (const [projectId, processes] of this.processesByProjectId.entries()) {
710	      const index = processes.findIndex((process) => process.processId === processId);
711	
712	      if (index === -1) {
713	        continue;
714	      }
715	
716	      const existing = processes[index];
717	
718	      if (existing === undefined) {
719	        continue;
720	      }
721	
722	      const now = new Date().toISOString();
723	      const nextProcess = processSummarySchema.parse({
724	        ...existing,
725	        status: 'running',
726	        phaseLabel: existing.phaseLabel === 'Draft' ? 'Working' : existing.phaseLabel,
727	        nextActionLabel: 'Monitor progress in the work surface',
728	        availableActions: ['open', 'review'],
729	        updatedAt: now,
730	      });
731	      const nextProcesses = [...processes];
732	      nextProcesses[index] = nextProcess;
733	      this.processesByProjectId.set(projectId, nextProcesses);
734	      this.currentRequestsByProcessId.set(processId, null);
735	      this.updateProjectSummary(projectId, (project) => ({
736	        ...project,
737	        lastUpdatedAt: now,
738	      }));
739	
740	      return {
741	        process: nextProcess,
742	        currentRequest: null,
743	      };
744	    }
745	
746	    const now = new Date().toISOString();
747	
748	    return {
749	      process: processSummarySchema.parse({
750	        processId,
751	        displayLabel: 'Unavailable process',
752	        processType: 'FeatureSpecification',
753	        status: 'running',
754	        phaseLabel: 'Working',
755	        nextActionLabel: 'Monitor progress in the work surface',
756	        availableActions: ['open', 'review'],
757	        hasEnvironment: false,
758	        updatedAt: now,
759	      }),
760	      currentRequest: null,
761	    };
762	  }
