220	function deriveAvailableActions(status: ProcessStatus): ProcessAvailableAction[] {
221	  switch (status) {
222	    case 'draft':
223	      return ['open'];
224	    case 'running':
225	      return ['open', 'review'];
226	    case 'waiting':
227	      return ['respond'];
228	    case 'paused':
229	      return ['resume'];
230	    case 'completed':
231	      return ['review'];
232	    case 'failed':
233	      return ['review', 'restart'];
234	    case 'interrupted':
235	      return ['resume', 'review', 'rehydrate', 'restart'];
236	    default:
237	      return [];
238	  }
