 80	async function captureUnhandledRejections(action: () => void | Promise<void>): Promise<unknown[]> {
 81	  const unhandledRejections: unknown[] = [];
 82	  const handler = (reason: unknown) => {
 83	    unhandledRejections.push(reason);
 84	  };
 85	
 86	  process.on('unhandledRejection', handler);
 87	
 88	  try {
 89	    await action();
 90	    await flush();
 91	    await flush();
 92	  } finally {
 93	    process.off('unhandledRejection', handler);
 94	  }
 95	
 96	  return unhandledRejections;
 97	}
