201	  private updateProjectSummary(
202	    projectId: string,
203	    update: (project: ProjectSummary) => ProjectSummary,
204	  ): void {
205	    for (const [userId, projects] of this.projectsByUserId.entries()) {
206	      this.projectsByUserId.set(
207	        userId,
208	        projects.map((project) => (project.projectId === projectId ? update(project) : project)),
209	      );
210	    }
211	
212	    const direct = this.accessByProjectId.get(projectId);
213	    if (direct?.kind === 'accessible') {
